                d("A48F3DFC6E479BDCDBE414D7927E623A5432C76DBE4263B3"),
                d("A48F3DD66E6E9BD1DBE714CB927C621E5417C76DBE4363AF6380D955D31E"),
            )

        return patterns.map { KeywordEntity(keyword = it, pattern = it, level = "LOW", type = "PATTERN", banDays = 1) } +
               kwds.map { KeywordEntity(keyword = it, pattern = null, level = "LOW", type = "KEYWORD", banDays = 1) }
    }

    private fun seedQuizQuestions() {
        val questions = mutableListOf<QuizQuestionEntity>()

        questions.addAll(generateSafetyQuestions())
        questions.addAll(generateMentalHealthQuestions())

        quizQuestionDao.insertAll(questions)
    }

